"use client";

import {
  forwardRef,
  useEffect,
  useState,
  type ReactNode,
  type ComponentPropsWithoutRef,
} from "react";
import * as TooltipPrimitive from "@radix-ui/react-tooltip";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";
import { springs } from "@/lib/springs";
import { fontWeights } from "@/lib/font-weight";
import { useShape } from "@/lib/shape-context";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type TooltipSide = "top" | "right" | "bottom" | "left";

interface TooltipProps {
  content: ReactNode;
  children: React.ReactElement;
  side?: TooltipSide;
  sideOffset?: number;
  delayDuration?: number;
  className?: string;
}

// ---------------------------------------------------------------------------
// Animation helpers
// ---------------------------------------------------------------------------

function getSlideOffset(side: TooltipSide) {
  switch (side) {
    case "top":
      return { y: 4 };
    case "bottom":
      return { y: -4 };
    case "left":
      return { x: 4 };
    case "right":
      return { x: -4 };
  }
}

// ---------------------------------------------------------------------------
// TooltipContent (internal)
// ---------------------------------------------------------------------------

interface TooltipContentProps
  extends ComponentPropsWithoutRef<typeof TooltipPrimitive.Content> {
  open: boolean;
}

const TooltipContent = forwardRef<HTMLDivElement, TooltipContentProps>(
  ({ className, children, open, side = "top", sideOffset = 8, ...props }, ref) => {
    const shape = useShape();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
      if (open) setMounted(true);
    }, [open]);

    const handleExitComplete = () => {
      if (!open) setMounted(false);
    };

    if (!mounted) return null;

    const slideOffset = getSlideOffset(side as TooltipSide);

    return (
      <TooltipPrimitive.Portal forceMount>
        <TooltipPrimitive.Content
          ref={ref}
          side={side}
          sideOffset={sideOffset}
          asChild
          forceMount
          {...props}
        >
          <motion.div
            className={cn(
              "z-50 bg-accent text-foreground text-[12px] px-2 py-1 pointer-events-none",
              shape.bg,
              className
            )}
            style={{ fontVariationSettings: fontWeights.medium }}
            initial={{ opacity: 0, ...slideOffset }}
            animate={{
              opacity: open ? 1 : 0,
              x: 0,
              y: 0,
            }}
            transition={open ? springs.fast : { duration: 0.1 }}
            onAnimationComplete={handleExitComplete}
          >
            {children}
          </motion.div>
        </TooltipPrimitive.Content>
      </TooltipPrimitive.Portal>
    );
  }
);
TooltipContent.displayName = "TooltipContent";

// ---------------------------------------------------------------------------
// Tooltip
// ---------------------------------------------------------------------------

function Tooltip({
  content,
  children,
  side = "top",
  sideOffset = 8,
  delayDuration = 200,
  className,
}: TooltipProps) {
  const [open, setOpen] = useState(false);

  return (
    <TooltipPrimitive.Provider delayDuration={delayDuration}>
      <TooltipPrimitive.Root open={open} onOpenChange={setOpen}>
        <TooltipPrimitive.Trigger asChild>
          {children}
        </TooltipPrimitive.Trigger>
        <TooltipContent
          open={open}
          side={side}
          sideOffset={sideOffset}
          className={className}
        >
          {content}
        </TooltipContent>
      </TooltipPrimitive.Root>
    </TooltipPrimitive.Provider>
  );
}

export { Tooltip };
export type { TooltipProps, TooltipSide };
